options.schemas:
{
  "attributes": [
    {
      "id": "title",
      "label": "Title",
      "placeholder": "Enter item title",
      "type": "text",
      "validationType": "string",
      "required": true,
      "validations": [
        {
          "type": "required",
          "params": [
            "Title is required"
          ]
        },
        {
          "type": "max",
          "params": [
            100,
            "Title cannot exceed 100 characters"
          ]
        },
        {
          "type": "default",
          "params": [
            "New Item"
          ]
        }
      ]
    },
    {
      "id": "url",
      "label": "URL",
      "placeholder": "Enter URL (e.g. /about)",
      "type": "text",
      "validationType": "string",
      "required": true,
      "validations": [
        {
          "type": "required",
          "params": [
            "URL is required"
          ]
        },
        {
          "type": "max",
          "params": [
            200,
            "URL cannot exceed 200 characters"
          ]
        },
        {
          "type": "default",
          "params": [
            "/"
          ]
        }
      ]
    },
    {
      "id": "target",
      "label": "Link Target",
      "type": "select",
      "validationType": "mixed",
      "value": "_self",
      "required": false,
      "validations": [
        {
          "type": "oneOf",
          "params": [
            [
              "_blank",
              "_self"
            ],
            "Must be _blank or _self"
          ]
        },
        {
          "type": "default",
          "params": [
            "_self"
          ]
        }
      ],
      "options": [
        {
          "key": "_self",
          "value": "_self",
          "metadatas": {
            "intlLabel": {
              "id": "tree-menus.target.options._self",
              "defaultMessage": "Same window (_self)"
            },
            "disabled": false,
            "hidden": false
          }
        },
        {
          "key": "_blank",
          "value": "_blank",
          "metadatas": {
            "intlLabel": {
              "id": "tree-menus.target.options._blank",
              "defaultMessage": "New window (_blank)"
            },
            "disabled": false,
            "hidden": false
          }
        }
      ]
    },
    {
      "id": "accessRole",
      "label": "Who can access this item",
      "type": "select",
      "validationType": "mixed",
      "value": "public",
      "required": true,
      "validations": [
        {
          "type": "oneOf",
          "params": [
            [
              "public",
              "visitor",
              "college-member"
            ],
            "Must be public, visitor, or college-member"
          ]
        },
        {
          "type": "default",
          "params": [
            "public"
          ]
        }
      ],
      "options": [
        {
          "key": "public",
          "value": "public",
          "metadatas": {
            "intlLabel": {
              "id": "tree-menus.accessRole.options.public",
              "defaultMessage": "Public"
            },
            "disabled": false,
            "hidden": false
          }
        },
        {
          "key": "visitor",
          "value": "visitor",
          "metadatas": {
            "intlLabel": {
              "id": "tree-menus.accessRole.options.visitor",
              "defaultMessage": "Visitor"
            },
            "disabled": false,
            "hidden": false
          }
        },
        {
          "key": "college-member",
          "value": "college-member",
          "metadatas": {
            "intlLabel": {
              "id": "tree-menus.accessRole.options.collegeMember",
              "defaultMessage": "College member"
            },
            "disabled": false,
            "hidden": false
          }
        }
      ]
    }
  ]
}
